from flask import Flask, redirect, request, session
import requests

app = Flask(__name__)
app.secret_key = 'your_secret_key'

AUTHORIZATION_SERVER_URL = 'https://authorization-server.com/oauth/authorize'
TOKEN_ENDPOINT = 'https://authorization-server.com/oauth/token'
CLIENT_ID = 'your_client_id'
CLIENT_SECRET = 'your_client_secret'
REDIRECT_URI = 'http://localhost:5000/callback'

@app.route('/login')
def login():
    scope = 'openid profile email'
    redirect_uri = f'{REDIRECT_URI}?response_type=code&client_id={CLIENT_ID}&scope={scope}'
    return redirect(redirect_uri)

@app.route('/callback')
def callback():
    code = request.args.get('code')
    token_data = {
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': REDIRECT_URI,
        'client_id': CLIENT_ID,
        'client_secret': CLIENT_SECRET
    }
    response = requests.post(TOKEN_ENDPOINT, data=token_data)
    if response.status_code == 200:
        access_token = response.json().get('access_token')
        session['access_token'] = access_token
        return 'Login successful!'
    else:
        return 'Login failed', 401

if __name__ == '__main__':
    app.run(debug=True)